import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { verifyToken } from "@/lib/auth";

// Platform fee rates: 15% on assessment/callout fees, 25% on work quotes
const ASSESSMENT_FEE_RATE = 0.15;
const WORK_QUOTE_RATE = 0.25;

// Helper to verify admin auth
async function verifyAdminAuth(request: NextRequest): Promise<boolean> {
  const token = request.cookies.get("auth_token")?.value;
  if (!token) return false;
  const payload = await verifyToken(token);
  return payload?.type === "admin";
}

interface LocksmithEarnings {
  locksmithId: string;
  locksmithName: string;
  companyName: string | null;
  email: string;
  jobCount: number;
  grossAmount: number;
  platformFee: number;
  netAmount: number;
  jobIds: string[];
  jobs: Array<{
    id: string;
    jobNumber: string;
    total: number;
    completedAt: Date;
  }>;
}

// GET - Preview pending earnings that would be included in payouts
export async function GET(request: NextRequest) {
  try {
    // Verify admin auth
    const isAdmin = await verifyAdminAuth(request);
    if (!isAdmin) {
      return NextResponse.json(
        { success: false, error: "Unauthorized" },
        { status: 401 }
      );
    }

    // Find all completed/signed jobs that haven't been paid out yet
    // A job is "paid out" if its ID appears in any payout's jobIds array
    const existingPayouts = await prisma.payout.findMany({
      select: { jobIds: true },
    });

    const paidOutJobIds = new Set(existingPayouts.flatMap((p) => p.jobIds));

    // Get completed jobs with payments
    const completedJobs = await prisma.job.findMany({
      where: {
        status: { in: ["COMPLETED", "SIGNED"] },
        locksmithId: { not: null },
      },
      include: {
        locksmith: {
          select: {
            id: true,
            name: true,
            companyName: true,
            email: true,
            stripeConnectId: true,
            stripeConnectOnboarded: true,
          },
        },
        payments: {
          where: { status: "succeeded" },
        },
        quote: true,
      },
      orderBy: { workCompletedAt: "desc" },
    });

    // Filter out jobs that have already been paid out
    const unpaidJobs = completedJobs.filter((job) => !paidOutJobIds.has(job.id));

    // Group by locksmith and calculate earnings
    const locksmithEarningsMap = new Map<string, LocksmithEarnings>();

    for (const job of unpaidJobs) {
      if (!job.locksmith) continue;

      const locksmithId = job.locksmith.id;

      // Calculate totals from succeeded payments, applying correct rate per type
      let jobTotal = 0;
      let platformFee = 0;
      for (const p of job.payments) {
        const rate = (p.type === "assessment" || p.type === "callout") ? ASSESSMENT_FEE_RATE : WORK_QUOTE_RATE;
        jobTotal += p.amount;
        platformFee += p.amount * rate;
      }

      if (jobTotal <= 0) continue;

      const netAmount = jobTotal - platformFee;

      if (!locksmithEarningsMap.has(locksmithId)) {
        locksmithEarningsMap.set(locksmithId, {
          locksmithId,
          locksmithName: job.locksmith.name,
          companyName: job.locksmith.companyName,
          email: job.locksmith.email,
          jobCount: 0,
          grossAmount: 0,
          platformFee: 0,
          netAmount: 0,
          jobIds: [],
          jobs: [],
        });
      }

      const earnings = locksmithEarningsMap.get(locksmithId)!;
      earnings.jobCount += 1;
      earnings.grossAmount += jobTotal;
      earnings.platformFee += platformFee;
      earnings.netAmount += netAmount;
      earnings.jobIds.push(job.id);
      earnings.jobs.push({
        id: job.id,
        jobNumber: job.jobNumber,
        total: jobTotal,
        completedAt: job.workCompletedAt || job.signedAt || job.createdAt,
      });
    }

    const pendingEarnings = Array.from(locksmithEarningsMap.values()).filter(
      (e) => e.netAmount > 0
    );

    // Sort by net amount descending
    pendingEarnings.sort((a, b) => b.netAmount - a.netAmount);

    // Calculate totals
    const totals = {
      totalLocksmiths: pendingEarnings.length,
      totalJobs: pendingEarnings.reduce((sum, e) => sum + e.jobCount, 0),
      totalGross: pendingEarnings.reduce((sum, e) => sum + e.grossAmount, 0),
      totalPlatformFees: pendingEarnings.reduce((sum, e) => sum + e.platformFee, 0),
      totalNet: pendingEarnings.reduce((sum, e) => sum + e.netAmount, 0),
    };

    return NextResponse.json({
      success: true,
      pendingEarnings,
      totals,
      message: pendingEarnings.length > 0
        ? `Found ${totals.totalJobs} unpaid jobs for ${totals.totalLocksmiths} locksmiths`
        : "No unpaid jobs found",
    });
  } catch (error) {
    console.error("Error fetching pending earnings:", error);
    return NextResponse.json(
      { success: false, error: "Failed to fetch pending earnings" },
      { status: 500 }
    );
  }
}

// POST - Generate pending payouts for selected or all locksmiths
export async function POST(request: NextRequest) {
  try {
    // Verify admin auth
    const isAdmin = await verifyAdminAuth(request);
    if (!isAdmin) {
      return NextResponse.json(
        { success: false, error: "Unauthorized" },
        { status: 401 }
      );
    }

    const body = await request.json();
    const { locksmithIds } = body; // Optional: specific locksmiths to generate payouts for

    // Find all completed/signed jobs that haven't been paid out yet
    const existingPayouts = await prisma.payout.findMany({
      select: { jobIds: true },
    });

    const paidOutJobIds = new Set(existingPayouts.flatMap((p) => p.jobIds));

    // Build query for completed jobs
    const whereClause: Record<string, unknown> = {
      status: { in: ["COMPLETED", "SIGNED"] },
      locksmithId: { not: null },
    };

    if (locksmithIds && Array.isArray(locksmithIds) && locksmithIds.length > 0) {
      whereClause.locksmithId = { in: locksmithIds };
    }

    const completedJobs = await prisma.job.findMany({
      where: whereClause,
      include: {
        locksmith: {
          select: {
            id: true,
            name: true,
            companyName: true,
            email: true,
          },
        },
        payments: {
          where: { status: "succeeded" },
        },
      },
    });

    // Filter out jobs that have already been paid out
    const unpaidJobs = completedJobs.filter((job) => !paidOutJobIds.has(job.id));

    // Group by locksmith
    const locksmithJobsMap = new Map<string, typeof unpaidJobs>();

    for (const job of unpaidJobs) {
      if (!job.locksmith) continue;

      const locksmithId = job.locksmith.id;
      if (!locksmithJobsMap.has(locksmithId)) {
        locksmithJobsMap.set(locksmithId, []);
      }
      locksmithJobsMap.get(locksmithId)!.push(job);
    }

    // Create payouts for each locksmith
    const createdPayouts = [];
    const now = new Date();
    const periodStart = new Date(now);
    periodStart.setDate(periodStart.getDate() - 7); // Last 7 days as default period

    // Pre-fetch team memberships for all locksmiths in this batch
    const batchLocksmithIds = Array.from(locksmithJobsMap.keys());
    const teamMemberships = await prisma.locksmithCompanyMember.findMany({
      where: {
        locksmithId: { in: batchLocksmithIds },
        isActive: true,
        role: "member", // Only sub-members get a split applied; owners pay themselves
      },
      include: {
        company: {
          select: { id: true, ownerId: true },
        },
      },
    });
    const membershipByLocksmith = new Map(
      teamMemberships.map((m) => [m.locksmithId, m])
    );

    // Accumulate manager top-ups keyed by ownerId
    const managerTopUps = new Map<
      string,
      { grossAmount: number; platformFee: number; netAmount: number; jobIds: string[]; periodStart: Date; periodEnd: Date }
    >();

    for (const [locksmithId, jobs] of locksmithJobsMap) {
      // Calculate total earnings from jobs, applying correct rate per payment type
      let grossAmount = 0;
      let platformFeeByType = 0; // 15% for assessment/callout, 25% for quote
      const jobIds: string[] = [];

      for (const job of jobs) {
        const jobTotal = job.payments.reduce((sum, p) => sum + p.amount, 0);
        if (jobTotal > 0) {
          grossAmount += jobTotal;
          jobIds.push(job.id);
          for (const p of job.payments) {
            const rate = (p.type === "assessment" || p.type === "callout") ? ASSESSMENT_FEE_RATE : WORK_QUOTE_RATE;
            platformFeeByType += p.amount * rate;
          }
        }
      }

      if (grossAmount <= 0 || jobIds.length === 0) continue;

      // Determine actual period from job dates
      const jobDates = jobs
        .map((j) => j.workCompletedAt || j.signedAt || j.createdAt)
        .filter(Boolean)
        .sort((a, b) => a.getTime() - b.getTime());

      const actualPeriodStart = jobDates[0] || periodStart;
      const actualPeriodEnd = jobDates[jobDates.length - 1] || now;

      // Check team membership — apply split if this locksmith is a sub-member
      // If a platformCommissionOverride is set, use that flat rate; otherwise use per-type rates
      const membership = membershipByLocksmith.get(locksmithId);
      const platformFee = membership?.platformCommissionOverride != null
        ? grossAmount * (membership.platformCommissionOverride / 100)
        : platformFeeByType;
      const netAfterPlatform = grossAmount - platformFee;

      let locksmithNetAmount: number;
      if (membership) {
        // Split: locksmith gets locksmithSplit%, manager keeps the rest
        locksmithNetAmount = netAfterPlatform * (membership.locksmithSplit / 100);
        const managerCut = netAfterPlatform - locksmithNetAmount;

        if (managerCut > 0 && membership.company.ownerId) {
          const ownerId = membership.company.ownerId;
          const existing = managerTopUps.get(ownerId);
          if (existing) {
            existing.grossAmount += managerCut;
            existing.platformFee += 0; // platform fee already deducted above
            existing.netAmount += managerCut;
            existing.jobIds.push(...jobIds);
            if (actualPeriodStart < existing.periodStart) existing.periodStart = actualPeriodStart;
            if (actualPeriodEnd > existing.periodEnd) existing.periodEnd = actualPeriodEnd;
          } else {
            managerTopUps.set(ownerId, {
              grossAmount: managerCut,
              platformFee: 0,
              netAmount: managerCut,
              jobIds: [...jobIds],
              periodStart: actualPeriodStart,
              periodEnd: actualPeriodEnd,
            });
          }
        }
      } else {
        locksmithNetAmount = netAfterPlatform;
      }

      const payout = await prisma.payout.create({
        data: {
          locksmithId,
          amount: grossAmount,
          platformFee,
          netAmount: locksmithNetAmount,
          status: "pending",
          periodStart: actualPeriodStart,
          periodEnd: actualPeriodEnd,
          jobIds,
        },
        include: {
          locksmith: {
            select: {
              name: true,
              companyName: true,
              email: true,
            },
          },
        },
      });

      createdPayouts.push(payout);
    }

    // Create manager payouts for accumulated team cuts
    for (const [ownerId, topUp] of managerTopUps) {
      // Skip if the owner themselves already has a payout in this batch
      if (locksmithJobsMap.has(ownerId)) continue;

      const ownerLocksmith = await prisma.locksmith.findUnique({
        where: { id: ownerId },
        select: { name: true, companyName: true, email: true },
      });
      if (!ownerLocksmith) continue;

      const payout = await prisma.payout.create({
        data: {
          locksmithId: ownerId,
          amount: topUp.grossAmount,
          platformFee: 0,
          netAmount: topUp.netAmount,
          status: "pending",
          periodStart: topUp.periodStart,
          periodEnd: topUp.periodEnd,
          jobIds: topUp.jobIds,
        },
        include: {
          locksmith: {
            select: {
              name: true,
              companyName: true,
              email: true,
            },
          },
        },
      });

      createdPayouts.push(payout);
    }

    return NextResponse.json({
      success: true,
      createdCount: createdPayouts.length,
      payouts: createdPayouts.map((p) => ({
        id: p.id,
        locksmithName: p.locksmith.name,
        companyName: p.locksmith.companyName,
        grossAmount: p.amount,
        platformFee: p.platformFee,
        netAmount: p.netAmount,
        jobCount: p.jobIds.length,
      })),
      message: createdPayouts.length > 0
        ? `Successfully created ${createdPayouts.length} pending payout(s)`
        : "No payouts to create - all jobs have already been paid out",
    });
  } catch (error) {
    console.error("Error generating payouts:", error);
    return NextResponse.json(
      { success: false, error: "Failed to generate payouts" },
      { status: 500 }
    );
  }
}
